namespace Components;

public class ShippingInfo
{
    public string Name { get; set; } = "";
    public string Address { get; set; } = "";
    public string City { get; set; } = "";
    public string ZipCode { get; set; } = "";
}

public class PaymentInfo
{
    public string CardNumber { get; set; } = "";
    public string ExpiryDate { get; set; } = "";
}

public class Order
{
    public ShippingInfo Shipping { get; set; } = new();
    public PaymentInfo Payment { get; set; } = new();
}

public interface IAddressValidator
{
    Task<bool> ValidateAddressAsync(string address, string city, string zip, CancellationToken ct);
}

@namespace Components

<div class="checkout-wizard">
    @if (_step == WizardStep.Shipping)
    {
        <ShippingStep Shipping="@_order.Shipping" OnNext="@HandleShippingComplete" />
    }
    else if (_step == WizardStep.Payment)
    {
        <PaymentStep Payment="@_order.Payment"
                     OnBack="@HandleBackToShipping"
                     OnPlaceOrder="@HandlePlaceOrder" />
    }
</div>

@code {
    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private Order _order = new();
    private WizardStep _step = WizardStep.Shipping;

    private enum WizardStep { Shipping, Payment }

    private void HandleShippingComplete()
    {
        _step = WizardStep.Payment;
    }

    private void HandleBackToShipping()
    {
        _step = WizardStep.Shipping;
    }

    private async Task HandlePlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

@namespace Components
@implements IDisposable
@inject IAddressValidator AddressValidator

<div class="shipping-step">
    <h3>Shipping Information</h3>

    <label>
        Name
        <input @bind="Shipping.Name" @bind:event="oninput" disabled="@_isValidating" />
    </label>

    <label>
        Address
        <input @bind="Shipping.Address" @bind:event="oninput" disabled="@_isValidating" />
    </label>

    <label>
        City
        <input @bind="Shipping.City" @bind:event="oninput" disabled="@_isValidating" />
    </label>

    <label>
        Zip Code
        <input @bind="Shipping.ZipCode" @bind:event="oninput" disabled="@_isValidating" />
    </label>

    @if (!string.IsNullOrEmpty(_validationError))
    {
        <p class="validation-error">@_validationError</p>
    }

    <button disabled="@_isValidating" @onclick="HandleNext">
        @if (_isValidating)
        {
            <span class="spinner" aria-label="Validating address…"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next</span>
        }
    </button>
</div>

@code {
    [Parameter]
    public ShippingInfo Shipping { get; set; } = new();

    [Parameter]
    public EventCallback OnNext { get; set; }

    private bool _isValidating;
    private string? _validationError;
    private CancellationTokenSource? _cts;

    private async Task HandleNext()
    {
        _validationError = null;

        // Cancel any previous in-flight validation
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _isValidating = true;
        StateHasChanged();

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _validationError = "The address could not be verified. Please check and try again.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was cancelled (user changed fields or navigated away) — do nothing.
        }
        finally
        {
            _isValidating = false;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

